module top_module(
  input in,
  output reg out  // Changed from wire to reg
);reg last_valid_state;

  always @(in) begin
    if (in === 1'b0 || in === 1'b1) begin
      last_valid_state <= in;
      out <= in;
    end
  end

  always @(*) begin
    if (in === 1'bx) begin
      out <= last_valid_state;
    end
  end

endmodule
